import math

def calculate_correlation_matrix(X, Y=None):
    if Y is None:
        Y = X

    n = len(X)
    n_x = len(X[0])
    n_y = len(Y[0])

    # Compute column means
    x_means = [sum(X[i][j] for i in range(n)) / n for j in range(n_x)]
    y_means = [sum(Y[i][j] for i in range(n)) / n for j in range(n_y)]

    # Compute population standard deviations
    x_stds = [
        math.sqrt(sum((X[i][j] - x_means[j]) ** 2 for i in range(n)) / n)
        for j in range(n_x)
    ]
    y_stds = [
        math.sqrt(sum((Y[i][j] - y_means[j]) ** 2 for i in range(n)) / n)
        for j in range(n_y)
    ]

    # Build correlation matrix: corr[j][k] = cov(X[:,j], Y[:,k]) / (std_xj * std_yk)
    corr = []
    for j in range(n_x):
        row = []
        for k in range(n_y):
            cov_jk = sum(
                (X[i][j] - x_means[j]) * (Y[i][k] - y_means[k])
                for i in range(n)
            ) / n
            denom = x_stds[j] * y_stds[k]
            row.append(cov_jk / denom if denom != 0 else 0.0)
        corr.append(row)

    return corr
